const book: BibleBook = {
  id: 'galatians',
  name: 'Gálatas',
  englishName: 'Galatians',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Paul, an apostle (not from men, nor through man, but through Jesus Christ, and God the Father, who raised him from the dead),', pt: 'Paulo, apóstolo (não da parte dos homens, nem por intermédio de homem algum, mas sim por Jesus Cristo, e por Deus Pai, que o ressuscitou dentre os mortos),' },
      { v: 2, en: 'and all the brothers who are with me, to the assemblies of Galatia:', pt: 'e todos os irmãos que estão comigo, às igrejas da Galácia:' },
      { v: 3, en: 'Grace to you and peace from God the Father, and our Lord Jesus Christ,', pt: 'Graça a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo,' },
      { v: 4, en: 'who gave himself for our sins, that he might deliver us out of this present evil age, according to the will of our God and Father—', pt: 'o qual se deu a si mesmo por nossos pecados, para nos livrar do presente século mau, segundo a vontade de nosso Deus e Pai,' },
      { v: 5, en: 'to whom be the glory forever and ever. Amen.', pt: 'a quem seja a glória para todo o sempre. Amém.' },
      { v: 6, en: 'I marvel that you are so quickly deserting him who called you in the grace of Christ to a different “good news”;', pt: 'Estou admirado de que tão depressa estejais desertando daquele que vos chamou na graça de Cristo, para outro evangelho,' },
      { v: 7, en: 'and there isn’t another “good news.” Only there are some who trouble you, and want to pervert the Good News of Christ.', pt: 'o qual não é outro; senão que há alguns que vos perturbam e querem perverter o evangelho de Cristo.' },
      { v: 8, en: 'But even though we, or an angel from heaven, should preach to you any “good news” other than that which we preached to you, let him be cursed.', pt: 'Mas, ainda que nós mesmos ou um anjo do céu vos pregasse outro evangelho além do que já vos pregamos, seja anátema.' },
      { v: 9, en: 'As we have said before, so I now say again: if any man preaches to you any “good news” other than that which you received, let him be cursed.', pt: 'Como antes temos dito, assim agora novamente o digo: Se alguém vos pregar outro evangelho além do que já recebestes, seja anátema.' },
      { v: 10, en: 'For am I now seeking the favor of men, or of God? Or am I striving to please men? For if I were still pleasing men, I wouldn’t be a servant of Christ.', pt: 'Pois busco eu agora o favor dos homens, ou o favor de Deus? ou procuro agradar aos homens? se estivesse ainda agradando aos homens, não seria servo de Cristo.' },
      { v: 11, en: 'But I make known to you, brothers, concerning the Good News which was preached by me, that it is not according to man.', pt: 'Mas faço-vos saber, irmãos, que o evangelho que por mim foi anunciado não é segundo os homens;' },
      { v: 12, en: 'For neither did I receive it from man, nor was I taught it, but it came to me through revelation of Jesus Christ.', pt: 'porque não o recebi de homem algum, nem me foi ensinado; mas o recebi por revelação de Jesus Cristo.' },
      { v: 13, en: 'For you have heard of my way of living in time past in the Jews’ religion, how that beyond measure I persecuted the assembly of God, and ravaged it.', pt: 'Pois já ouvistes qual foi outrora o meu procedimento no judaísmo, como sobremaneira perseguia a igreja de Deus e a assolava,' },
      { v: 14, en: 'I advanced in the Jews’ religion beyond many of my own age among my countrymen, being more exceedingly zealous for the traditions of my fathers.', pt: 'e na minha nação excedia em judaísmo a muitos da minha idade, sendo extremamente zeloso das tradições de meus pais.' },
      { v: 15, en: 'But when it was the good pleasure of God, who separated me from my mother’s womb, and called me through his grace,', pt: 'Mas, quando aprouve a Deus, que desde o ventre de minha mãe me separou, e me chamou pela sua graça,' },
      { v: 16, en: 'to reveal his Son in me, that I might preach him among the Gentiles, I didn’t immediately confer with flesh and blood,', pt: 'revelar seu Filho em mim, para que eu o pregasse entre os gentios, não consultei carne e sangue,' },
      { v: 17, en: 'nor did I go up to Jerusalem to those who were apostles before me, but I went away into Arabia. Then I returned to Damascus.', pt: 'nem subi a Jerusalém para estar com os que já antes de mim eram apóstolos, mas parti para a Arábia, e voltei outra vez a Damasco.' },
      { v: 18, en: 'Then after three years I went up to Jerusalem to visit Peter, and stayed with him fifteen days.', pt: 'Depois, passados três anos, subi a Jerusalém para visitar a Cefas, e demorei com ele quinze dias.' },
      { v: 19, en: 'But of the other apostles I saw no one, except James, the Lord’s brother.', pt: 'Mas não vi a nenhum outro dos apóstolos, senão a Tiago, irmão do Senhor.' },
      { v: 20, en: 'Now about the things which I write to you, behold, before God, I’m not lying.', pt: 'Ora, acerca do que vos escrevo, eis que diante de Deus testifico que não minto.' },
      { v: 21, en: 'Then I came to the regions of Syria and Cilicia.', pt: 'Depois fui para as regiões da Síria e da Cilícia.' },
      { v: 22, en: 'I was still unknown by face to the assemblies of Judea which were in Christ,', pt: 'Não era conhecido de vista das igrejas de Cristo na Judéia;' },
      { v: 23, en: 'but they only heard: “He who once persecuted us now preaches the faith that he once tried to destroy.”', pt: 'mas somente tinham ouvido dizer: Aquele que outrora nos perseguia agora prega a fé que antes procurava destruir;' },
      { v: 24, en: 'And they glorified God in me.', pt: 'e glorificavam a Deus a respeito de mim.' },
    ],
    2: [
      { v: 1, en: 'Then after a period of fourteen years I went up again to Jerusalem with Barnabas, taking Titus also with me.', pt: 'Depois, passados catorze anos, subi outra vez a Jerusalém com Barnabé, levando também comigo a Tito.' },
      { v: 2, en: 'I went up by revelation, and I laid before them the Good News which I preach among the Gentiles, but privately before those who were respected, for fear that I might be running, or had run, in vain.', pt: 'E subi devido a uma revelação, e lhes expus o evangelho que prego entre os gentios, mas em particular aos que eram de destaque, para que de algum modo não estivesse correndo ou não tivesse corrido em vão.' },
      { v: 3, en: 'But not even Titus, who was with me, being a Greek, was compelled to be circumcised.', pt: 'Mas nem mesmo Tito, que estava comigo, embora sendo grego, foi constrangido a circuncidar-se;' },
      { v: 4, en: 'This was because of the false brothers secretly brought in, who stole in to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage;', pt: 'e isto por causa dos falsos irmãos intrusos, os quais furtivamente entraram a espiar a nossa liberdade, que temos em Cristo Jesus, para nos escravizar;' },
      { v: 5, en: 'to whom we gave no place in the way of subjection, not for an hour, that the truth of the Good News might continue with you.', pt: 'aos quais nem ainda por uma hora cedemos em sujeição, para que a verdade do evangelho permanecesse entre vós.' },
      { v: 6, en: 'But from those who were reputed to be important (whatever they were, it makes no difference to me; God doesn’t show partiality to man)—they, I say, who were respected imparted nothing to me,', pt: 'Ora, daqueles que pareciam ser alguma coisa (quais outrora tenham sido, nada me importa; Deus não aceita a aparência do homem), esses, digo, que pareciam ser alguma coisa, nada me acrescentaram;' },
      { v: 7, en: 'but to the contrary, when they saw that I had been entrusted with the Good News for the uncircumcised, even as Peter with the Good News for the circumcised', pt: 'antes, pelo contrário, quando viram que o evangelho da incircuncisão me fora confiado, como a Pedro o da circuncisão' },
      { v: 8, en: '(for he who worked through Peter in the apostleship with the circumcised also worked through me with the Gentiles);', pt: '(porque aquele que operou a favor de Pedro para o apostolado da circuncisão, operou também a meu favor para com os gentios),' },
      { v: 9, en: 'and when they perceived the grace that was given to me, James and Cephas and John, they who were reputed to be pillars, gave to me and Barnabas the right hand of fellowship, that we should go to the Gentiles, and they to the circumcision.', pt: 'e quando conheceram a graça que me fora dada, Tiago, Cefas e João, que pareciam ser as colunas, deram a mim e a Barnabé as destras de comunhão, para que nós fôssemos aos gentios, e eles à circuncisão;' },
      { v: 10, en: 'They only asked us to remember the poor—which very thing I was also zealous to do.', pt: 'recomendando-nos somente que nos lembrássemos dos pobres; o que também procurei fazer com diligência.' },
      { v: 11, en: 'But when Peter came to Antioch, I resisted him to his face, because he stood condemned.', pt: 'Quando, porém, Cefas veio a Antioquia, resisti-lhe na cara, porque era repreensível.' },
      { v: 12, en: 'For before some people came from James, he ate with the Gentiles. But when they came, he drew back and separated himself, fearing those who were of the circumcision.', pt: 'Pois antes de chegarem alguns da parte de Tiago, ele comia com os gentios; mas quando eles chegaram, se foi retirando e se apartava deles, temendo os que eram da circuncisão.' },
      { v: 13, en: 'And the rest of the Jews joined him in his hypocrisy; so that even Barnabas was carried away with their hypocrisy.', pt: 'E os outros judeus também dissimularam com ele, de modo que até Barnabé se deixou levar pela sua dissimulação.' },
      { v: 14, en: 'But when I saw that they didn’t walk uprightly according to the truth of the Good News, I said to Peter before them all, “If you, being a Jew, live as the Gentiles do, and not as the Jews do, why do you compel the Gentiles to live as the Jews do?', pt: 'Mas, quando vi que não andavam retamente conforme a verdade do evangelho, disse a Cefas perante todos: Se tu, sendo judeu, vives como os gentios, e não como os judeus, como é que obrigas os gentios a viverem como judeus?' },
      { v: 15, en: '“We, being Jews by nature, and not Gentile sinners,', pt: 'Nós, judeus por natureza e não pecadores dentre os gentios,' },
      { v: 16, en: 'yet knowing that a man is not justified by the works of the law but through faith in Jesus Christ, even we believed in Christ Jesus, that we might be justified by faith in Christ, and not by the works of the law, because no flesh will be justified by the works of the law.', pt: 'sabendo, contudo, que o homem não é justificado por obras da lei, mas sim, pela fé em Cristo Jesus, temos também crido em Cristo Jesus para sermos justificados pela fé em Cristo, e não por obras da lei; pois por obras da lei nenhuma carne será justificada.' },
      { v: 17, en: 'But if, while we sought to be justified in Christ, we ourselves also were found sinners, is Christ a servant of sin? Certainly not!', pt: 'Mas se, procurando ser justificados em Cristo, fomos nós mesmos também achados pecadores, é porventura Cristo ministro do pecado? De modo nenhum.' },
      { v: 18, en: 'For if I build up again those things which I destroyed, I prove myself a law-breaker.', pt: 'Porque, se torno a edificar aquilo que destruí, constituo-me a mim mesmo transgressor.' },
      { v: 19, en: 'For I, through the law, died to the law, that I might live to God.', pt: 'Pois eu pela lei morri para a lei, a fim de viver para Deus.' },
      { v: 20, en: 'I have been crucified with Christ, and it is no longer I that live, but Christ lives in me. That life which I now live in the flesh, I live by faith in the Son of God, who loved me, and gave himself up for me.', pt: 'Já estou crucificado com Cristo; e vivo, não mais eu, mas Cristo vive em mim; e a vida que agora vivo na carne, vivo-a na fé no filho de Deus, o qual me amou, e se entregou a si mesmo por mim.' },
      { v: 21, en: 'I don’t reject the grace of God. For if righteousness is through the law, then Christ died for nothing!”', pt: 'Não faço nula a graça de Deus; porque, se a justiça vem mediante a lei, logo Cristo morreu em vão.' },
    ],
    3: [
      { v: 1, en: 'Foolish Galatians, who has bewitched you not to obey the truth, before whose eyes Jesus Christ was openly portrayed among you as crucified?', pt: 'ó insensatos gálatas! quem vos fascinou a vós, ante cujos olhos foi representado Jesus Cristo como crucificado?' },
      { v: 2, en: 'I just want to learn this from you: Did you receive the Spirit by the works of the law, or by hearing of faith?', pt: 'Só isto quero saber de vós: Foi por obras da lei que recebestes o Espírito, ou pelo ouvir com fé?' },
      { v: 3, en: 'Are you so foolish? Having begun in the Spirit, are you now completed in the flesh?', pt: 'Sois vós tão insensatos? tendo começado pelo Espírito, é pela carne que agora acabareis?' },
      { v: 4, en: 'Did you suffer so many things in vain, if it is indeed in vain?', pt: 'Será que padecestes tantas coisas em vão? Se é que isso foi em vão.' },
      { v: 5, en: 'He therefore who supplies the Spirit to you, and does miracles among you, does he do it by the works of the law, or by hearing of faith?', pt: 'Aquele pois que vos dá o Espírito, e que opera milagres entre vós, acaso o faz pelas obras da lei, ou pelo ouvir com fé?' },
      { v: 6, en: 'Even as Abraham “believed God, and it was counted to him for righteousness.”', pt: 'Assim como Abraão creu a Deus, e isso lhe foi imputado como justiça.' },
      { v: 7, en: 'Know therefore that those who are of faith, the same are children of Abraham.', pt: 'Sabei, pois, que os que são da fé, esses são filhos de Abraão.' },
      { v: 8, en: 'The Scripture, foreseeing that God would justify the Gentiles by faith, preached the Good News beforehand to Abraham, saying, “In you all the nations will be blessed.”', pt: 'Ora, a Escritura, prevendo que Deus havia de justificar pela fé os gentios, anunciou previamente a boa nova a Abraão, dizendo: Em ti serão abençoadas todas as nações.' },
      { v: 9, en: 'So then, those who are of faith are blessed with the faithful Abraham.', pt: 'De modo que os que são da fé são abençoados com o crente Abraão.' },
      { v: 10, en: 'For as many as are of the works of the law are under a curse. For it is written, “Cursed is everyone who doesn’t continue in all things that are written in the book of the law, to do them.”', pt: 'Pois todos quantos são das obras da lei estão debaixo da maldição; porque escrito está: Maldito todo aquele que não permanece em todas as coisas que estão escritas no livro da lei, para fazê-las.' },
      { v: 11, en: 'Now that no man is justified by the law before God is evident, for, “The righteous will live by faith.”', pt: 'É evidente que pela lei ninguém é justificado diante de Deus, porque: O justo viverá da fé;' },
      { v: 12, en: 'The law is not of faith, but, “The man who does them will live by them.”', pt: 'ora, a lei não é da fé, mas: O que fizer estas coisas, por elas viverá.' },
      { v: 13, en: 'Christ redeemed us from the curse of the law, having become a curse for us. For it is written, “Cursed is everyone who hangs on a tree,”', pt: 'Cristo nos resgatou da maldição da lei, fazendo-se maldição por nós; porque está escrito: Maldito todo aquele que for pendurado no madeiro;' },
      { v: 14, en: 'that the blessing of Abraham might come on the Gentiles through Christ Jesus; that we might receive the promise of the Spirit through faith.', pt: 'para que aos gentios viesse a bênção de Abraão em Jesus Cristo, a fim de que nós recebêssemos pela fé a promessa do Espírito.' },
      { v: 15, en: 'Brothers, speaking of human terms, though it is only a man’s covenant, yet when it has been confirmed, no one makes it void, or adds to it.', pt: 'Irmãos, como homem falo. Um testamento, embora de homem, uma vez confirmado, ninguém o anula, nem lhe acrescenta coisa alguma.' },
      { v: 16, en: 'Now the promises were spoken to Abraham and to his offspring. He doesn’t say, “To descendants ”, as of many, but as of one, “To your offspring ”, which is Christ.', pt: 'Ora, a Abraão e a seu descendente foram feitas as promessas; não diz: E a seus descendentes, como falando de muitos, mas como de um só: E a teu descendente, que é Cristo.' },
      { v: 17, en: 'Now I say this: A covenant confirmed beforehand by God in Christ, the law, which came four hundred thirty years after, does not annul, so as to make the promise of no effect.', pt: 'E digo isto: Ao testamento anteriormente confirmado por Deus, a lei, que veio quatrocentos e trinta anos depois, não invalida, de forma a tornar inoperante a promessa.' },
      { v: 18, en: 'For if the inheritance is of the law, it is no more of promise; but God has granted it to Abraham by promise.', pt: 'Pois se da lei provém a herança, já não provém mais da promessa; mas Deus, pela promessa, a deu gratuitamente a Abraão.' },
      { v: 19, en: 'Then why is there the law? It was added because of transgressions, until the offspring should come to whom the promise has been made. It was ordained through angels by the hand of a mediator.', pt: 'Logo, para que é a lei? Foi acrescentada por causa das transgressões, até que viesse o descendente a quem a promessa tinha sido feita; e foi ordenada por meio de anjos, pela mão de um mediador.' },
      { v: 20, en: 'Now a mediator is not between one, but God is one.', pt: 'Ora, o mediador não o é de um só, mas Deus é um só.' },
      { v: 21, en: 'Is the law then against the promises of God? Certainly not! For if there had been a law given which could make alive, most certainly righteousness would have been of the law.', pt: 'É a lei, então, contra as promessas de Deus? De modo nenhum; porque, se fosse dada uma lei que pudesse vivificar, a justiça, na verdade, teria sido pela lei.' },
      { v: 22, en: 'But the Scriptures imprisoned all things under sin, that the promise by faith in Jesus Christ might be given to those who believe.', pt: 'Mas a Escritura encerrou tudo debaixo do pecado, para que a promessa pela fé em Jesus Cristo fosse dada aos que crêem.' },
      { v: 23, en: 'But before faith came, we were kept in custody under the law, confined for the faith which should afterwards be revealed.', pt: 'Mas, antes que viesse a fé, estávamos guardados debaixo da lei, encerrados para aquela fé que se havia de revelar.' },
      { v: 24, en: 'So that the law has become our tutor to bring us to Christ, that we might be justified by faith.', pt: 'De modo que a lei se tornou nosso aio, para nos conduzir a Cristo, a fim de que pela fé fôssemos justificados.' },
      { v: 25, en: 'But now that faith has come, we are no longer under a tutor.', pt: 'Mas, depois que veio a fé, já não estamos debaixo de aio.' },
      { v: 26, en: 'For you are all children of God, through faith in Christ Jesus.', pt: 'Pois todos sois filhos de Deus pela fé em Cristo Jesus.' },
      { v: 27, en: 'For as many of you as were baptized into Christ have put on Christ.', pt: 'Porque todos quantos fostes batizados em Cristo vos revestistes de Cristo.' },
      { v: 28, en: 'There is neither Jew nor Greek, there is neither slave nor free man, there is neither male nor female; for you are all one in Christ Jesus.', pt: 'Não há judeu nem grego; não há escravo nem livre; não há homem nem mulher; porque todos vós sois um em Cristo Jesus.' },
      { v: 29, en: 'If you are Christ’s, then you are Abraham’s offspring and heirs according to promise.', pt: 'E, se sois de Cristo, então sois descendência de Abraão, e herdeiros conforme a promessa.' },
    ],
    4: [
      { v: 1, en: 'But I say that so long as the heir is a child, he is no different from a bondservant, though he is lord of all;', pt: 'Ora, digo que por todo o tempo em que o herdeiro é menino, em nada difere de um servo, ainda que seja senhor de tudo;' },
      { v: 2, en: 'but is under guardians and stewards until the day appointed by the father.', pt: 'mas está debaixo de tutores e curadores até o tempo determinado pelo pai.' },
      { v: 3, en: 'So we also, when we were children, were held in bondage under the elemental principles of the world.', pt: 'Assim também nós, quando éramos meninos, estávamos reduzidos à servidão debaixo dos rudimentos do mundo;' },
      { v: 4, en: 'But when the fullness of the time came, God sent out his Son, born to a woman, born under the law,', pt: 'mas, vindo a plenitude dos tempos, Deus enviou seu Filho, nascido de mulher, nascido debaixo de lei,' },
      { v: 5, en: 'that he might redeem those who were under the law, that we might receive the adoption of children.', pt: 'para resgatar os que estavam debaixo de lei, a fim de recebermos a adoção de filhos.' },
      { v: 6, en: 'And because you are children, God sent out the Spirit of his Son into your hearts, crying, “Abba, Father!”', pt: 'E, porque sois filhos, Deus enviou aos nossos corações o Espírito de seu Filho, que clama: Aba, Pai.' },
      { v: 7, en: 'So you are no longer a bondservant, but a son; and if a son, then an heir of God through Christ.', pt: 'Portanto já não és mais servo, mas filho; e se és filho, és também herdeiro por Deus.' },
      { v: 8, en: 'However at that time, not knowing God, you were in bondage to those who by nature are not gods.', pt: 'Outrora, quando não conhecíeis a Deus, servíeis aos que por natureza não são deuses;' },
      { v: 9, en: 'But now that you have come to know God, or rather to be known by God, why do you turn back again to the weak and miserable elemental principles, to which you desire to be in bondage all over again?', pt: 'agora, porém, que já conheceis a Deus, ou, melhor, sendo conhecidos por Deus, como tornais outra vez a esses rudimentos fracos e pobres, aos quais de novo quereis servir?' },
      { v: 10, en: 'You observe days, months, seasons, and years.', pt: 'Guardais dias, e meses, e tempos, e anos.' },
      { v: 11, en: 'I am afraid for you, that I might have wasted my labor for you.', pt: 'Temo a vosso respeito não haja eu trabalhado em vão entre vós.' },
      { v: 12, en: 'I beg you, brothers, become as I am, for I also have become as you are. You did me no wrong,', pt: 'Irmãos, rogo-vos que vos torneis como eu, porque também eu me tornei como vós. Nenhum mal me fizestes;' },
      { v: 13, en: 'but you know that because of weakness in the flesh I preached the Good News to you the first time.', pt: 'e vós sabeis que por causa de uma enfermidade da carne vos anunciei o evangelho a primeira vez,' },
      { v: 14, en: 'That which was a temptation to you in my flesh, you didn’t despise nor reject; but you received me as an angel of God, even as Christ Jesus.', pt: 'e aquilo que na minha carne era para vós uma tentação, não o desprezastes nem o repelistes, antes me recebestes como a um anjo de Deus, mesmo como a Cristo Jesus.' },
      { v: 15, en: 'What was the blessing you enjoyed? For I testify to you that, if possible, you would have plucked out your eyes and given them to me.', pt: 'Onde está, pois, aquela vossa satisfação? Porque vos dou testemunho de que, se possível fora, teríeis arrancado os vossos olhos, e mos teríeis dado.' },
      { v: 16, en: 'So then, have I become your enemy by telling you the truth?', pt: 'Tornei-me acaso vosso inimigo, porque vos disse a verdade?' },
      { v: 17, en: 'They zealously seek you in no good way. No, they desire to alienate you, that you may seek them.', pt: 'Eles vos procuram zelosamente não com bons motivos, mas querem vos excluir, para que zelosamente os procureis a eles.' },
      { v: 18, en: 'But it is always good to be zealous in a good cause, and not only when I am present with you.', pt: 'No que é bom, é bom serdes sempre procurados, e não só quando estou presente convosco.' },
      { v: 19, en: 'My little children, of whom I am again in travail until Christ is formed in you—', pt: 'Meus filhinhos, por quem de novo sinto as dores de parto, até que Cristo seja formado em vós;' },
      { v: 20, en: 'but I could wish to be present with you now, and to change my tone, for I am perplexed about you.', pt: 'eu bem quisera estar presente convosco agora, e mudar o tom da minha voz; porque estou perplexo a vosso respeito.' },
      { v: 21, en: 'Tell me, you that desire to be under the law, don’t you listen to the law?', pt: 'Dizei-me, os que quereis estar debaixo da lei, não ouvis vós a lei?' },
      { v: 22, en: 'For it is written that Abraham had two sons, one by the servant, and one by the free woman.', pt: 'Porque está escrito que Abraão teve dois filhos, um da escrava, e outro da livre.' },
      { v: 23, en: 'However, the son by the servant was born according to the flesh, but the son by the free woman was born through promise.', pt: 'Todavia o que era da escrava nasceu segundo a carne, mas, o que era da livre, por promessa.' },
      { v: 24, en: 'These things contain an allegory, for these are two covenants. One is from Mount Sinai, bearing children to bondage, which is Hagar.', pt: 'O que se entende por alegoria: pois essas mulheres são dois pactos; um do monte Sinai, que dá à luz filhos para a servidão, e que é Agar.' },
      { v: 25, en: 'For this Hagar is Mount Sinai in Arabia, and answers to the Jerusalem that exists now, for she is in bondage with her children.', pt: 'Ora, esta Agar é o monte Sinai na Arábia e corresponde à Jerusalém atual, pois é escrava com seus filhos.' },
      { v: 26, en: 'But the Jerusalem that is above is free, which is the mother of us all.', pt: 'Mas a Jerusalém que é de cima é livre; a qual é nossa mãe.' },
      { v: 27, en: 'For it is written, “Rejoice, you barren who don’t bear. Break out and shout, you that don’t travail. For more are the children of the desolate than of her who has a husband.”', pt: 'Pois está escrito: Alegra-te, estéril, que não dás à luz; esforça-te e clama, tu que não estás de parto; porque mais são os filhos da desolada do que os da que tem marido.' },
      { v: 28, en: 'Now we, brothers, as Isaac was, are children of promise.', pt: 'Ora vós, irmãos, sois filhos da promessa, como Isaque.' },
      { v: 29, en: 'But as then, he who was born according to the flesh persecuted him who was born according to the Spirit, so also it is now.', pt: 'Mas, como naquele tempo o que nasceu segundo a carne perseguia ao que nasceu segundo o Espírito, assim é também agora.' },
      { v: 30, en: 'However what does the Scripture say? “Throw out the servant and her son, for the son of the servant will not inherit with the son of the free woman.”', pt: 'Que diz, porém, a Escritura? Lança fora a escrava e seu filho, porque de modo algum o filho da escrava herdará com o filho da livre.' },
      { v: 31, en: 'So then, brothers, we are not children of a servant, but of the free woman.', pt: 'Pelo que, irmãos, não somos filhos da escrava, mas da livre.' },
    ],
    5: [
      { v: 1, en: 'Stand firm therefore in the liberty by which Christ has made us free, and don’t be entangled again with a yoke of bondage.', pt: 'Para a liberdade Cristo nos libertou; permanecei, pois, firmes e não vos dobreis novamente a um jogo de escravidão.' },
      { v: 2, en: 'Behold, I, Paul, tell you that if you receive circumcision, Christ will profit you nothing.', pt: 'Eis que eu, Paulo, vos digo que, se vos deixardes circuncidar, Cristo de nada vos aproveitará.' },
      { v: 3, en: 'Yes, I testify again to every man who receives circumcision, that he is a debtor to do the whole law.', pt: 'E de novo testifico a todo homem que se deixa circuncidar, que está obrigado a guardar toda a lei.' },
      { v: 4, en: 'You are alienated from Christ, you who desire to be justified by the law. You have fallen away from grace.', pt: 'Separados estais de Cristo, vós os que vos justificais pela lei; da graça decaístes.' },
      { v: 5, en: 'For we, through the Spirit, by faith wait for the hope of righteousness.', pt: 'Nós, entretanto, pelo Espírito aguardamos a esperança da justiça que provém da fé.' },
      { v: 6, en: 'For in Christ Jesus neither circumcision amounts to anything, nor uncircumcision, but faith working through love.', pt: 'Porque em Cristo Jesus nem a circuncisão nem a incircuncisão vale coisa alguma; mas sim a fé que opera pelo amor.' },
      { v: 7, en: 'You were running well! Who interfered with you that you should not obey the truth?', pt: 'Corríeis bem; quem vos impediu de obedecer à verdade?' },
      { v: 8, en: 'This persuasion is not from him who calls you.', pt: 'Esta persuasão não vem daquele que vos chama.' },
      { v: 9, en: 'A little yeast grows through the whole lump.', pt: 'Um pouco de fermento leveda a massa toda.' },
      { v: 10, en: 'I have confidence toward you in the Lord that you will think no other way. But he who troubles you will bear his judgment, whoever he is.', pt: 'Confio de vós, no Senhor, que de outro modo não haveis de pensar; mas aquele que vos perturba, seja quem for, sofrerá a condenação.' },
      { v: 11, en: 'But I, brothers, if I still preach circumcision, why am I still persecuted? Then the stumbling block of the cross has been removed.', pt: 'Eu, porém, irmãos, se é que prego ainda a circuncisão, por que ainda sou perseguido? Nesse caso o escândalo da cruz estaria aniquilado.' },
      { v: 12, en: 'I wish that those who disturb you would cut themselves off.', pt: 'Oxalá se mutilassem aqueles que vos andam inquietando.' },
      { v: 13, en: 'For you, brothers, were called for freedom. Only don’t use your freedom for gain to the flesh, but through love be servants to one another.', pt: 'Porque vós, irmãos, fostes chamados à liberdade. Mas não useis da liberdade para dar ocasião à carne, antes pelo amor servi-vos uns aos outros.' },
      { v: 14, en: 'For the whole law is fulfilled in one word, in this: “You shall love your neighbor as yourself.”', pt: 'Pois toda a lei se cumpre numa só palavra, a saber: Amarás ao teu próximo como a ti mesmo.' },
      { v: 15, en: 'But if you bite and devour one another, be careful that you don’t consume one another.', pt: 'Se vós, porém, vos mordeis e devorais uns aos outros, vede não vos consumais uns aos outros.' },
      { v: 16, en: 'But I say, walk by the Spirit, and you won’t fulfill the lust of the flesh.', pt: 'Digo, porém: Andai pelo Espírito, e não haveis de cumprir a cobiça da carne.' },
      { v: 17, en: 'For the flesh lusts against the Spirit, and the Spirit against the flesh; and these are contrary to one another, that you may not do the things that you desire.', pt: 'Porque a carne luta contra o Espírito, e o Espírito contra a carne; e estes se opõem um ao outro, para que não façais o que quereis.' },
      { v: 18, en: 'But if you are led by the Spirit, you are not under the law.', pt: 'Mas, se sois guiados pelo Espírito, não estais debaixo da lei.' },
      { v: 19, en: 'Now the deeds of the flesh are obvious, which are: adultery, sexual immorality, uncleanness, lustfulness,', pt: 'Ora, as obras da carne são manifestas, as quais são: a prostituição, a impureza, a lascívia,' },
      { v: 20, en: 'idolatry, sorcery, hatred, strife, jealousies, outbursts of anger, rivalries, divisions, heresies,', pt: 'a idolatria, a feitiçaria, as inimizades, as contendas, os ciúmes, as iras, as facções, as dissensões, os partidos,' },
      { v: 21, en: 'envy, murders, drunkenness, orgies, and things like these; of which I forewarn you, even as I also forewarned you, that those who practice such things will not inherit God’s Kingdom.', pt: 'as invejas, as bebedices, as orgias, e coisas semelhantes a estas, contra as quais vos previno, como já antes vos preveni, que os que tais coisas praticam não herdarão o reino de Deus.' },
      { v: 22, en: 'But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faith,', pt: 'Mas o fruto do Espírito é: o amor, o gozo, a paz, a longanimidade, a benignidade, a bondade, a fidelidade.' },
      { v: 23, en: 'gentleness, and self-control. Against such things there is no law.', pt: 'a mansidão, o domínio próprio; contra estas coisas não há lei.' },
      { v: 24, en: 'Those who belong to Christ have crucified the flesh with its passions and lusts.', pt: 'E os que são de Cristo Jesus crucificaram a carne com as suas paixões e concupiscências.' },
      { v: 25, en: 'If we live by the Spirit, let’s also walk by the Spirit.', pt: 'Se vivemos pelo Espírito, andemos também pelo Espírito.' },
      { v: 26, en: 'Let’s not become conceited, provoking one another, and envying one another.', pt: 'Não nos tornemos vangloriosos, provocando-nos uns aos outros, invejando-nos uns aos outros.' },
    ],
    6: [
      { v: 1, en: 'Brothers, even if a man is caught in some fault, you who are spiritual must restore such a one in a spirit of gentleness; looking to yourself so that you also aren’t tempted.', pt: 'Irmãos, se um homem chegar a ser surpreendido em algum delito, vós que sois espirituais corrigi o tal com espírito de mansidão; e olha por ti mesmo, para que também tu não sejas tentado.' },
      { v: 2, en: 'Bear one another’s burdens, and so fulfill the law of Christ.', pt: 'Levai as cargas uns dos outros, e assim cumprireis a lei de Cristo.' },
      { v: 3, en: 'For if a man thinks himself to be something when he is nothing, he deceives himself.', pt: 'Pois, se alguém pensa ser alguma coisa, não sendo nada, engana-se a si mesmo.' },
      { v: 4, en: 'But let each man examine his own work, and then he will have reason to boast in himself, and not in someone else.', pt: 'Mas prove cada um a sua própria obra, e então terá motivo de glória somente em si mesmo, e não em outrem;' },
      { v: 5, en: 'For each man will bear his own burden.', pt: 'porque cada qual levará o seu próprio fardo.' },
      { v: 6, en: 'But let him who is taught in the word share all good things with him who teaches.', pt: 'E o que está sendo instruído na palavra, faça participante em todas as boas coisas aquele que o instrui.' },
      { v: 7, en: 'Don’t be deceived. God is not mocked, for whatever a man sows, that he will also reap.', pt: 'Não vos enganeis; Deus não se deixa escarnecer; pois tudo o que o homem semear, isso também ceifará.' },
      { v: 8, en: 'For he who sows to his own flesh will from the flesh reap corruption. But he who sows to the Spirit will from the Spirit reap eternal life.', pt: 'Porque quem semeia na sua carne, da carne ceifará a corrupção; mas quem semeia no Espírito, do Espírito ceifará a vida eterna.' },
      { v: 9, en: 'Let us not be weary in doing good, for we will reap in due season, if we don’t give up.', pt: 'E não nos cansemos de fazer o bem, porque a seu tempo ceifaremos, se não houvermos desfalecido.' },
      { v: 10, en: 'So then, as we have opportunity, let’s do what is good toward all men, and especially toward those who are of the household of the faith.', pt: 'Então, enquanto temos oportunidade, façamos bem a todos, mas principamente aos domésticos da fé.' },
      { v: 11, en: 'See with what large letters I write to you with my own hand.', pt: 'Vede com que grandes letras vos escrevo com minha própria mão.' },
      { v: 12, en: 'As many as desire to make a good impression in the flesh compel you to be circumcised; just so they may not be persecuted for the cross of Christ.', pt: 'Todos os que querem ostentar boa aparência na carne, esses vos obrigam a circuncidar-vos, somente para não serem perseguidos por causa da cruz de Cristo.' },
      { v: 13, en: 'For even they who receive circumcision don’t keep the law themselves, but they desire to have you circumcised, that they may boast in your flesh.', pt: 'Porque nem ainda esses mesmos que se circuncidam guardam a lei, mas querem que vos circuncideis, para se gloriarem na vossa carne.' },
      { v: 14, en: 'But far be it from me to boast, except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world.', pt: 'Mas longe esteja de mim gloriar-me, a não ser na cruz de nosso Senhor Jesus Cristo, pela qual o mundo está crucificado para mim e eu para o mundo.' },
      { v: 15, en: 'For in Christ Jesus neither is circumcision anything, nor uncircumcision, but a new creation.', pt: 'Pois nem a circuncisão nem a incircuncisão é coisa alguma, mas sim o ser uma nova criatura.' },
      { v: 16, en: 'As many as walk by this rule, peace and mercy be on them, and on God’s Israel.', pt: 'E a todos quantos andarem conforme esta norma, paz e misericórdia sejam sobre eles e sobre o Israel de Deus.' },
      { v: 17, en: 'From now on, let no one cause me any trouble, for I bear the marks of the Lord Jesus branded on my body.', pt: 'Daqui em diante ninguém me moleste; porque eu trago no meu corpo as marcas de Jesus.' },
      { v: 18, en: 'The grace of our Lord Jesus Christ be with your spirit, brothers. Amen.', pt: 'A graça de nosso Senhor Jesus Cristo seja, irmãos, com o vosso espírito. Amém.' },
    ],
  },
};

export default book;
